"use strict";parserFactory.register("brittanypage43.com",()=>new Brittanypage43Parser);class Brittanypage43Parser extends Parser{constructor(){super()}disabled(){return UIText.Warning.parserDisabledNotification}async getChapterUrls(e){return[...e.querySelectorAll("a.post-card-content-link")].map(this.linkToChapter).reverse()}linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector(".post-card-title").textContent.trim()}}findContent(e){return e.querySelector(".gh-content")}extractTitleImpl(e){return e.querySelector(".post-card-large header h2")}findChapterTitle(e){return e.querySelector(".article-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".post-card-image-link")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".post-card-excerpt")]}}